"use client"
import React, { useEffect, useState } from 'react'
import KakaoMap from '@/components/map/KakaoMap';
import '../../../../css/home/main.css';
import './modal.css'
import DetailMap from '@/components/map/DetailMap';


const page = () => {

    const [pharmacies, setPharmacies] = useState<any[]>([]);
    const [selectedPharmacy, setSelectedPharmacy] = useState<any>(null);

    const closeModal = () => setSelectedPharmacy(null);

    // when pharmacies data update...refix


    return (
        
        <div className="parmacy-container">
            <div className="container" style={{ padding: '60px 30px' }}>


                <div style={{ marginBottom: '40px', textAlign: 'center' }}>
                <h2 className="section-title">내 주변 약국 찾기</h2>
                <p style={{ color: '#666', marginTop: '10px' }}>
                    현재 위치를 기반으로 운영 중인 약국을 찾아드립니다.<br />
                    지도에서 위치를 검색하면 아래에 목록이 표시됩니다.
                </p>
            </div>
            {/* map section */}
                <div style={{ 
                width: '100%', 
                borderRadius: '16px', 
                overflow: 'hidden', 
                boxShadow: '0 4px 20px rgba(0,0,0,0.08)',
                border: '2px solid #c7def7',
                
                }}>
                    <KakaoMap onPharmaciesLoaded={setPharmacies} />
                </div>

                  
            </div>

            {/* List Section*/}
            <div style={{ marginTop: '40px' }}>
            <h3 style={{ fontSize: '1.4rem', marginBottom: '20px', fontFamily: 'Do Hyeon, sans-serif', padding: '20px'}}>
                🏥 검색된 약국 목록 ({pharmacies.length}개)
            </h3>

            {pharmacies.length === 0 ? (
                <div style={{ textAlign: 'center', padding: '40px', color: '#999', background: '#f9f9f9', borderRadius: '12px'}}>
                주변에 약국이 없거나 데이터를 불러오는 중입니다.
                </div>
            ) : (

                <ul style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))', gap: '20px', listStyle: 'none', padding: '20px'}}>
              
                
                {pharmacies.map((pharmacy) => (
                    
                    
                    
                    <li key={pharmacy.id} style={{ 
                        background: 'white', padding: '20px', borderRadius: '12px', 
                        border: '1px solid #eee', boxShadow: '0 2px 8px rgba(0,0,0,0.05)',
                        transition: 'transform 0.2s'
                    }}>
                        {/* <pre style={{ fontSize: '10px', background: '#eee' }}>
                        {JSON.stringify(pharmacy, null, 2)}
                    </pre> */}
                    
                    

                    <strong style={{ display: 'block', fontSize: '1.1rem', color: '#333', marginBottom: '8px' }}>
                        {pharmacy.place_name}
                    </strong>
                    <p style={{ fontSize: '0.9rem', color: '#666', marginBottom: '4px' }}>
                        🚩 {pharmacy.distance+'m' || '거리 정보없음'}
                    </p>
                    <p style={{ fontSize: '0.9rem', color: '#666', marginBottom: '4px' }}>
                        📞 {pharmacy.phone || '정보 없음'}
                    </p>
                    <p style={{ fontSize: '0.9rem', color: '#888', marginBottom: '12px' }}>
                        📍 {pharmacy.road_address_name || pharmacy.address_name}
                    </p>

                    <button 
                        onClick={() => setSelectedPharmacy(pharmacy)}
                        style={{ 
                            padding: '8px 16px', background: '#2563eb', border: 'none', cursor: 'pointer',
                            color: 'white', borderRadius: '6px', fontSize: '0.9rem', fontWeight: 'bold'
                        }}
                    >
                        
                        상세보기
                    </button>
                    </li>
                ))}
                </ul>
            )}
            </div>
    
      {selectedPharmacy && (
        <div className="modal-overlay" onClick={closeModal}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()} style={{ maxWidth: '500px' }}>
            
            {/* 헤더 */}
            <div className="modal-header">
              <h2>{selectedPharmacy.place_name}</h2>
              <button className="close-btn" onClick={closeModal}>✕</button>
            </div>

            {/* 내용 */}
            <div style={{ padding: '10px 0', lineHeight: '1.8', fontSize: '1rem', color: '#444' }}>

                <DetailMap
                lat={parseFloat(selectedPharmacy.y)} 
                lng={parseFloat(selectedPharmacy.x)} 
              />
              
              <p><strong>🚩 거리:</strong> {selectedPharmacy.distance+'m' || '거리 정보없음'}</p>
              <p><strong>📍 도로명 주소:</strong> {selectedPharmacy.road_address_name || '-'}</p>
              <p><strong>🏠 지번 주소:</strong> {selectedPharmacy.address_name}</p>
              <p><strong>📞 전화번호:</strong> {selectedPharmacy.phone || '정보 없음'}</p>
              <p><strong>🔗 카카오맵 ID:</strong> {selectedPharmacy.id}</p>
              
              <div style={{ marginTop: '20px', padding: '15px', background: '#f0f7ff', borderRadius: '8px', fontSize: '0.9rem' }}>
                <p>※ 상세 영업시간이나 휴일 정보는<br/>카카오맵 공식 페이지에서 확인하실 수 있습니다.</p>
              </div>

              {/* 하단 버튼 그룹 */}
              <div style={{ display: 'flex', gap: '10px', marginTop: '20px' }}>
                <a 
                    href={selectedPharmacy.place_url} 
                    target="_blank" 
                    rel="noreferrer"
                    style={{ 
                        flex: 1, textAlign: 'center', padding: '12px', background: '#fee500', 
                        color: '#000', textDecoration: 'none', borderRadius: '8px', fontWeight: 'bold' 
                    }}
                >
                    카카오맵으로 보기
                </a>
                <button 
                    onClick={closeModal}
                    style={{ 
                        flex: 1, padding: '12px', background: '#eee', border: 'none',
                        color: '#333', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' 
                    }}
                >
                    닫기
                </button>
              </div>
            </div>

          </div>
        </div>
      )}

        <div className="container" style={{ marginTop: '30px', padding: '0 20px' }}>
            <div style={{ padding: '20px', backgroundColor: '#f9f9f9', borderRadius: '8px', fontSize: '0.9rem', color: '#888' }}>
                <strong style={{ display: 'block', marginBottom: '8px', color: '#555' }}>💡 이용 안내</strong>
                <ul style={{ listStyle: 'none', padding: 0, margin: 0, lineHeight: '1.6' }}>
                    <li>• 위치 정보 권한을 허용해야 내 주변 약국이 검색됩니다.</li>
                    <li>• 지도에 표시된 마커를 클릭하면 전화번호와 상세 주소를 볼 수 있습니다.</li>
                    <li>• 데이터 제공: Kakao Maps API</li>
                </ul>
            </div>
        </div>
    </div>
    
  );
};

export default page;